+    ? resolveInside(baseDir, sanitizeManifestPath(options.path))
+    : baseDir;
+
+  const direct = await readSkill(searchRoot, baseDir);
+  const skills = new Map<string, DiscoveredSkill>();
+  if (direct) {
+    skills.set(direct.name.toLowerCase(), direct);
