+  if (!options.skillNames || options.skillNames.length === 0) {
+    return found;
+  }
+
+  const requested = new Set(options.skillNames.map((name) => name.toLowerCase()));
+  return found.filter((skill) => requested.has(skill.name.toLowerCase()));
