+/**
+ * ASCII banner for AI-PKGS CLI.
+ *
+ * This mirrors Story's banner renderer: a 6-row block-art wordmark rendered
+ * with a row-by-row RGB gradient. The art uses an ANSI-shadow style so the
+ * logo has the heavier depth the interactive prompts need.
+ */
+
+/**
+ * Block-art rendering of "AI-PKGS" (6 rows). Generated once and checked in so
+ * runtime startup does not need a figlet dependency.
+ */
+export const BANNER_LINES: readonly string[] = Object.freeze([
+  ' █████╗ ██╗      ██████╗ ██╗  ██╗ ██████╗ ███████╗',
+  '██╔══██╗██║      ██╔══██╗██║ ██╔╝██╔════╝ ██╔════╝',
+  '███████║██║█████╗██████╔╝█████╔╝ ██║  ███╗███████╗',
+  '██╔══██║██║╚════╝██╔═══╝ ██╔═██╗ ██║   ██║╚════██║',
+  '██║  ██║██║      ██║     ██║  ██╗╚██████╔╝███████║',
+  '╚═╝  ╚═╝╚═╝      ╚═╝     ╚═╝  ╚═╝ ╚═════╝ ╚══════╝',
+]);
+
+/**
+ * Story-compatible sky-cyan ramp: mid-dark at top, brightest in the middle,
+ * then back down. This reads well on dark and light terminal themes.
+ */
+export const GRADIENT: readonly (readonly [number, number, number])[] =
+  Object.freeze([
+    [84, 167, 205],
+    [96, 191, 224],
+    [116, 211, 242],
+    [148, 223, 248],
+    [116, 211, 242],
+    [96, 191, 224],
+  ] as const);
+
+const RESET = '\x1B[0m';
+
+export function rgb(r: number, g: number, b: number): string {
+  if (!isColorEnabled()) {
+    return '';
+  }
+
+  return `\x1B[38;2;${r};${g};${b}m`;
+}
+
+export function renderBannerLines(forceColor = false): string[] {
+  return BANNER_LINES.map((line, index) => {
+    const tint = GRADIENT[index];
+    if (!tint) {
+      return line;
+    }
+
+    const [r, g, b] = tint;
+    const prefix = forceColor ? `\x1B[38;2;${r};${g};${b}m` : rgb(r, g, b);
+    const suffix = prefix === '' ? '' : RESET;
+    return `${prefix}${line}${suffix}`;
+  });
+}
+
+export function renderLogo(forceColor = false): string {
+  return renderBannerLines(forceColor).join('\n');
+}
+
+export function banner(
+  out: NodeJS.WritableStream = process.stdout,
+  force = false
+): void {
+  if (!force && !isWritableTTY(out)) {
+    return;
+  }
+
+  for (const line of renderBannerLines(force)) {
+    out.write(`${line}\n`);
+  }
+  out.write('\n');
+}
+
+function isColorEnabled(): boolean {
+  if (process.env.NO_COLOR || process.env.TERM === 'dumb') {
+    return false;
+  }
+
+  return (
+    process.env.FORCE_COLOR !== undefined ||
+    (process.stdout as unknown as { isTTY?: boolean }).isTTY === true
+  );
+}
+
+function isWritableTTY(out: NodeJS.WritableStream): boolean {
+  return (out as unknown as { isTTY?: boolean }).isTTY === true;
+}
